### Describe the bug

Prior to PR #4708 you could access redirect headers with `beforeRedirect: (options, { headers })` but with the changes in #4708 the `headers` are no longer available. To me it's unclear whether this was an intentional change or not but the documentation suggests that this should still be working. 

### To Reproduce

https://npm.runkit.com/axios

```javascript
var axios = require("axios")
// Works with an older version
// var axios = require("axios@0.27.2")
var express = require("express")
var app = express()

app.get('/redirect', (req, res) => {
  res.cookie("Hello", "World");
  res.redirect("/");
})

app.get('/', (req, res) => {
  res.send('Hello World!')
})

app.listen(3000, () => {
    axios.get("http://localhost:3000/redirect", {
        // Headers undefined
        beforeRedirect: (options, { headers }) => {
            console.log({options, headers});
        }
    });
});
```

### Describe the bug

When removing defaults, i.e. axios.defaults.headers and then using retry logic `instance(originalConfig)` or `instance.request(originalConfig)` with already processed headers within a response interceptor error, the axios code creates invalid `config.headers: { [object Object]: undefined }`.

Invalid axios code on retry (lib/core/Axios.js):
```
    // Flatten headers
    const defaultHeaders = config.headers && utils.merge(
      config.headers.common, //<--- is undefined
      config.headers[config.method] //<--- is undefined
    );

    defaultHeaders && utils.forEach(
      ['delete', 'get', 'head', 'post', 'put', 'patch', 'common'],
      function cleanHeaderConfig(method) {
        delete config.headers[method];
      }
    );

    //config.headers still valid on retry
    config.headers = new AxiosHeaders(config.headers, defaultHeaders); //problem here!
    //config.headers invalid ([object Object]: undefined) on retry
```

There needs to be a check beforehand if `config.headers.common` and / or `config.headers[config.method]` exists before merging.

